package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Closeable;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterCloseTest {

    private CSVFormat format;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void close_whenOutIsCloseable_shouldCallClose() throws IOException {
        Closeable closeableOut = mock(Closeable.class);
        CSVPrinter printer = new CSVPrinter(new AppendableCloseableWrapper(closeableOut), format);

        printer.close();

        verify(closeableOut, times(1)).close();
    }

    @Test
    void close_whenOutIsNotCloseable_shouldNotThrow() {
        Appendable nonCloseableOut = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) { return this; }
            @Override
            public Appendable append(CharSequence csq, int start, int end) { return this; }
            @Override
            public Appendable append(char c) { return this; }
        };
        CSVPrinter printer = new CSVPrinter(nonCloseableOut, format);

        assertDoesNotThrow(() -> printer.close());
    }

    // Wrapper class to make Closeable also implement Appendable
    private static class AppendableCloseableWrapper implements Appendable, Closeable {
        private final Closeable closeable;

        AppendableCloseableWrapper(Closeable closeable) {
            this.closeable = closeable;
        }

        @Override
        public Appendable append(CharSequence csq) {
            return this;
        }

        @Override
        public Appendable append(CharSequence csq, int start, int end) {
            return this;
        }

        @Override
        public Appendable append(char c) {
            return this;
        }

        @Override
        public void close() throws IOException {
            closeable.close();
        }
    }
}
